messages.message:
Patch Set 1:

I agree osp needs not to be changed.  The thing is, when processing a non-full log, _llog_ has no idea if any newly added records will be cancelled by another thread.  Thus, from llog's point of view, only save local copies of llh_count for full logs does not solve the issue for non-full log case.

On the other hand, is something like this acceptable?

  --- a/lustre/obdclass/llog.c
  +++ b/lustre/obdclass/llog.c
  @@ -362,6 +362,11 @@ repeat:
                                  rc = lpi->lpi_cb(lpi->lpi_env, loghandle, rec,
                                                   lpi->lpi_cbdata);
                                  last_called_index = index;
  +                               if (!llog_exist(loghandle)) {
  +                                       LASSERT(rc != LLOG_PROC_BREAK);
  +                                       llog_close(lpi->lpi_env, loghandle);
  +                                       GOTO(out, rc);
  +                               }
                                  if (rc == LLOG_PROC_BREAK) {
                                          GOTO(out, rc);
                                  } else if (rc == LLOG_DEL_RECORD) {
  diff --git a/lustre/obdclass/llog_cat.c b/lustre/obdclass/llog_cat.c
  index cc065c1..536385d 100644
  --- a/lustre/obdclass/llog_cat.c
  +++ b/lustre/obdclass/llog_cat.c
  @@ -521,7 +521,8 @@ int llog_cat_cancel_records(const struct lu_env *env,
                          if (cathandle->u.chd.chd_current_log == loghandle)
                                  cathandle->u.chd.chd_current_log = NULL;
                          cfs_up_write(&cathandle->lgh_lock);
  -                       llog_close(env, loghandle);
  +                       if (loghandle->lgh_cur_idx == 0)
  +                               llog_close(env, loghandle);

                          LASSERT(index);
                          llog_cat_set_first_idx(cathandle, index);
